const items = $input.all().map(item => item.json);

function clean(value) {
  return String(value ?? "").trim();
}

function upper(value) {
  return clean(value).toUpperCase();
}

function toNumber(value) {
  const n = Number(String(value ?? "").replace(",", "."));
  return Number.isNaN(n) ? 0 : n;
}

function normalizeDate(value) {
  const v = clean(value);

  if (/^\d{2}\/\d{2}\/\d{4}$/.test(v)) return v;

  if (/^\d{4}-\d{2}-\d{2}$/.test(v)) {
    const [y, m, d] = v.split("-");
    return `${d}/${m}/${y}`;
  }

  return v;
}

// Separar los items mezclados del Append
const camareros = items.filter(i =>
  i.telefono !== undefined && i.fecha_evento !== undefined
);

const eventos = items.filter(i =>
  i.event_id !== undefined
);

// 1. Filtrar eventos NEW reales
const eventosNew = eventos
  .filter(e => clean(e.event_id) !== "")
  .filter(e => upper(e.estado) === "NEW");

// 2. Agrupar eventos por fecha
const eventosPorFecha = {};

for (const e of eventosNew) {
  const fecha = normalizeDate(e.fecha);
  if (!fecha) continue;

  if (!eventosPorFecha[fecha]) {
    eventosPorFecha[fecha] = [];
  }

  eventosPorFecha[fecha].push({
    event_id: clean(e.event_id),
    fecha,
    hora_inicio: clean(e.hora_inicio),
    hora_fin: clean(e.hora_fin),
    tipo: clean(e.tipo),
    nombre_evento: clean(e.nombre_evento),
    ubicacion: clean(e.ubicacion),
    asistentes: toNumber(e.asistentes),
    camareros_necesarios: toNumber(e.camareros_necesarios),
    prioridad: toNumber(e.prioridad),
    observaciones: clean(e.observaciones),
  });
}

// 3. Construir salida por fecha
const salida = [];

for (const [fecha, listaEventos] of Object.entries(eventosPorFecha)) {
  const camarerosValidos = camareros
    .filter(c => normalizeDate(c.fecha_evento) === fecha)
    .filter(c => upper(c.disponible) === "SI")
    .filter(c => upper(c.activo) === "SI")
    .filter(c => upper(c.verificado) === "SI")
    .map(c => ({
      telefono: clean(c.telefono),
      nombre: clean(c.nombre),
      tiene_coche: upper(c.tiene_coche) === "SI",
      observaciones: clean(c.observaciones),

      fecha_alta: clean(c.fecha_alta),
      antiguedad_dias: toNumber(c.antiguedad_dias),
      horas_trabajadas: toNumber(c.horas_trabajadas),
      nota: toNumber(c.nota),

      fecha_ultimo_evento: clean(c.fecha_ultimo_evento),
      dias_desde_ultimo_evento: toNumber(c.dias_desde_ultimo_evento),

      fecha_ultima_disponibilidad_si: clean(c.fecha_ultima_disponibilidad_si),
      dias_desde_ultima_disponibilidad_si: toNumber(c.dias_desde_ultima_disponibilidad_si),

      num_disponibilidades_si: toNumber(c.num_disponibilidades_si),
      num_respuestas: toNumber(c.num_respuestas),
      ratio_disponibilidad: toNumber(c.ratio_disponibilidad),
      num_disponibilidades_coche: toNumber(c.num_disponibilidades_coche),

      score_fiable: toNumber(c.score_fiable),
      score_prometedor: toNumber(c.score_prometedor),
      score_general: toNumber(c.score_general),
    }))
    .filter(c => c.telefono !== "");

  // Orden para ayudar al modelo
  camarerosValidos.sort((a, b) => {
    if (b.score_general !== a.score_general) return b.score_general - a.score_general;
    if (b.score_fiable !== a.score_fiable) return b.score_fiable - a.score_fiable;
    return b.nota - a.nota;
  });

  // prioridad alta primero
  listaEventos.sort((a, b) => b.prioridad - a.prioridad);

  salida.push({
    json: {
      fecha,
      eventos: listaEventos,
      total_eventos: listaEventos.length,
      camareros_validos: camarerosValidos,
      total_camareros_validos: camarerosValidos.length,
    }
  });
}

return salida;

const raw = $json.content.parts[0].text;

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error("Respuesta de Gemini no es JSON válido");
}

return [
  {
    json: parsed
  }
];

const items = $input.all();

let asignaciones = null;
let eventos = null;
let camareros = null;

for (const item of items) {
  if (item.json.asignaciones) {
    asignaciones = item.json.asignaciones;
  }

  if (item.json.eventos) {
    eventos = item.json.eventos;
  }

  if (item.json.camareros_validos) {
    camareros = item.json.camareros_validos;
  }
}

return [
  {
    json: {
      asignaciones,
      eventos,
      camareros_validos: camareros
    }
  }
];

function clean(value) {
  return String(value ?? "").trim();
}

function toNumber(value) {
  const n = Number(String(value ?? "").replace(",", "."));
  return Number.isNaN(n) ? 0 : n;
}

function boolLike(value) {
  if (typeof value === "boolean") return value;
  const v = clean(value).toUpperCase();
  return v === "SI" || v === "TRUE" || v === "1";
}

return items.map((item) => {

  const eventos = item.json.eventos || [];
  const camareros = item.json.camareros_validos || [];
  const asignaciones = item.json.asignaciones || [];

  const errores = [];
  const warnings = [];

  // INDEXES
  const eventosPorId = {};
  for (const e of eventos) {
    eventosPorId[clean(e.event_id)] = e;
  }

  const camarerosPorTelefono = {};
  for (const c of camareros) {
    camarerosPorTelefono[clean(c.telefono)] = c;
  }

  // CONTROL GLOBAL DE DUPLICADOS
  const telefonosUsados = new Set();
  const telefonosDuplicados = new Set();

  for (const asignacion of asignaciones) {

    const eventId = clean(asignacion.event_id);
    const asignados = asignacion.asignados || [];

    const evento = eventosPorId[eventId];

    if (!evento) {
      errores.push(`Evento inexistente: ${eventId}`);
      continue;
    }

    const necesarios = toNumber(evento.camareros_necesarios);
    const cochesMinimos = Math.ceil(necesarios / 5);

    // Nº camareros exacto
    if (asignados.length !== necesarios) {
      errores.push(`Evento ${eventId}: necesita ${necesarios} y tiene ${asignados.length}`);
    }

    // Duplicados dentro del evento
    const telefonosEvento = asignados.map(a => clean(a.telefono));
    const setEvento = new Set(telefonosEvento);

    if (telefonosEvento.length !== setEvento.size) {
      errores.push(`Evento ${eventId}: teléfonos repetidos dentro del evento`);
    }

    let coches = 0;

    for (const a of asignados) {

      const telefono = clean(a.telefono);

      if (!telefono) {
        errores.push(`Evento ${eventId}: teléfono vacío`);
        continue;
      }

      const real = camarerosPorTelefono[telefono];

      // Existe en candidatos
      if (!real) {
        errores.push(`Evento ${eventId}: teléfono ${telefono} no existe`);
        continue;
      }

      // Duplicado global
      if (telefonosUsados.has(telefono)) {
        telefonosDuplicados.add(telefono);
      } else {
        telefonosUsados.add(telefono);
      }

      // Validar nombre
      if (clean(a.nombre) !== clean(real.nombre)) {
        errores.push(`Evento ${eventId}: nombre incorrecto para ${telefono}`);
      }

      // Validar score
      if (Math.abs(toNumber(a.score_general) - toNumber(real.score_general)) > 0.0001) {
        errores.push(`Evento ${eventId}: score incorrecto para ${telefono}`);
      }

      // Validar coche
      if (boolLike(a.tiene_coche) !== boolLike(real.tiene_coche)) {
        errores.push(`Evento ${eventId}: coche incorrecto para ${telefono}`);
      }

      if (boolLike(real.tiene_coche)) coches++;
    }

    // Coches mínimos
    if (coches < cochesMinimos) {
      errores.push(`Evento ${eventId}: necesita ${cochesMinimos} coches y tiene ${coches}`);
    }
  }

  // Eventos sin asignación
  const eventosAsignados = new Set(asignaciones.map(a => clean(a.event_id)));

  for (const e of eventos) {
    const id = clean(e.event_id);
    if (!eventosAsignados.has(id)) {
      errores.push(`Evento sin asignación: ${id}`);
    }
  }

  // Duplicados entre eventos
  if (telefonosDuplicados.size > 0) {
    errores.push(`Teléfonos duplicados: ${Array.from(telefonosDuplicados).join(", ")}`);
  }

  // RESUMEN
  const resumen = asignaciones.map(a => {
    const asignados = a.asignados || [];

    return {
      event_id: a.event_id,
      num_asignados: asignados.length,
      score_total: Number(
        asignados.reduce((acc, x) => acc + toNumber(x.score_general), 0).toFixed(3)
      ),
      coches: asignados.filter(x => boolLike(x.tiene_coche)).length
    };
  });

  return {
    json: {
      ...item.json,
      validacion: {
        valido: errores.length === 0,
        num_errores: errores.length,
        errores,
        resumen_por_evento: resumen
      }
    }
  };
});

function clean(value) {
  return String(value ?? "").trim();
}

function toNumber(value) {
  const n = Number(String(value ?? "").replace(",", "."));
  return Number.isNaN(n) ? 0 : n;
}

function boolLike(value) {
  if (typeof value === "boolean") return value;
  const v = clean(value).toUpperCase();
  return v === "SI" || v === "TRUE" || v === "1";
}

return items.map((item) => {
  const fecha = item.json.fecha || item.json.eventos?.[0]?.fecha || null;
  const eventos = [...(item.json.eventos || [])];
  const candidatos = [...(item.json.camareros_validos || [])];

  if (eventos.length === 0) {
    throw new Error("Fallback: no hay eventos");
  }

  if (candidatos.length === 0) {
    throw new Error("Fallback: no hay camareros_validos");
  }

  const errores = [];

  // 🔹 Orden global de candidatos
  candidatos.sort((a, b) => {
    if (toNumber(b.score_general) !== toNumber(a.score_general)) {
      return toNumber(b.score_general) - toNumber(a.score_general);
    }
    if (toNumber(b.score_fiable) !== toNumber(a.score_fiable)) {
      return toNumber(b.score_fiable) - toNumber(a.score_fiable);
    }
    if (toNumber(b.nota) !== toNumber(a.nota)) {
      return toNumber(b.nota) - toNumber(a.nota);
    }
    return toNumber(a.horas_trabajadas) - toNumber(b.horas_trabajadas);
  });

  // 🔹 Prioridad eventos
  eventos.sort((a, b) => toNumber(b.prioridad) - toNumber(a.prioridad));

  const usados = new Set();
  const asignaciones = [];

  for (const evento of eventos) {
    const eventId = clean(evento.event_id);
    const necesarios = toNumber(evento.camareros_necesarios);
    const cochesMinimos = Math.ceil(necesarios / 5);

    const disponibles = candidatos.filter(c => !usados.has(clean(c.telefono)));

    // 1️⃣ Seleccionar primero con coche
    const seleccionados = [];
    const conCoche = disponibles.filter(c => boolLike(c.tiene_coche));

    for (const c of conCoche) {
      if (seleccionados.length >= cochesMinimos) break;
      seleccionados.push(c);
    }

    if (seleccionados.length < cochesMinimos) {
      errores.push(`No hay suficientes camareros con coche para ${eventId}`);
      continue;
    }

    // 2️⃣ Completar con mejores restantes
    const yaSeleccionados = new Set(seleccionados.map(c => clean(c.telefono)));

    for (const c of disponibles) {
      if (seleccionados.length >= necesarios) break;

      const tel = clean(c.telefono);
      if (yaSeleccionados.has(tel)) continue;

      seleccionados.push(c);
      yaSeleccionados.add(tel);
    }

    if (seleccionados.length < necesarios) {
      errores.push(`No hay suficientes camareros para ${eventId}`);
      continue;
    }

    // 3️⃣ Marcar usados
    for (const s of seleccionados) {
      usados.add(clean(s.telefono));
    }

    // 4️⃣ Guardar asignación
    asignaciones.push({
      event_id: eventId,
      asignados: seleccionados.map(s => ({
        telefono: clean(s.telefono),
        nombre: clean(s.nombre),
        score_general: toNumber(s.score_general),
        tiene_coche: boolLike(s.tiene_coche)
      }))
    });
  }

  const resumen = asignaciones.map(a => ({
    event_id: a.event_id,
    num_asignados: a.asignados.length,
    score_total: Number(
      a.asignados.reduce((acc, x) => acc + toNumber(x.score_general), 0).toFixed(3)
    ),
    coches: a.asignados.filter(x => boolLike(x.tiene_coche)).length
  }));

  return {
    json: {
      ...item.json,
      origen_asignacion: "fallback",
      asignaciones_finales: asignaciones,
      fallback: {
        ejecutado: true,
        valido: errores.length === 0,
        num_errores: errores.length,
        errores,
        resumen_por_evento: resumen
      }
    }
  };
});

return items.map(item => ({
  json: {
    ...item.json,
    origen_asignacion: "ia",
    asignaciones_finales: item.json.asignaciones || []
  }
}));

return items.map(item => ({
  json: {
    ...item.json,
    origen_asignacion: "fallback",
    asignaciones_finales: item.json.asignaciones_fallback || []
  }
}));

const salida = [];

for (const item of items) {
  const fecha = item.json.fecha;
  const origen = item.json.origen_asignacion;
  const asignaciones = item.json.asignaciones_finales || [];

  for (const asignacion of asignaciones) {
    const eventId = asignacion.event_id;

    for (const persona of asignacion.asignados) {
      salida.push({
        json: {
          fecha,
          event_id: eventId,
          telefono: persona.telefono,
          nombre: persona.nombre,
          score_general: persona.score_general,
          tiene_coche: persona.tiene_coche,
          origen_asignacion: origen
        }
      });
    }
  }
}

return salida;
